def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    term = np.tanh(((ratio - a) ** 6) / (a * b + 1)) * np.sin(ratio * b / (a + 1.5))
                    priority += term * np.cos(a * b / (ratio + 0.7))
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 1.8
        elif 5 < ratio <= 8:
            for c in range(2, int(np.floor(ratio)) + 5):
                for d in range(1, c + 3):
                    val = ((ratio - c) ** 4) / (d + 0.7) * np.cos(ratio * d) * np.tanh(ratio / (c + 1))
                    priority += np.tanh(val) * 1.7
            priority += np.log(ratio + 1) * 12 - np.tanh(ratio - 5) * 3
        elif 2 < ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 2) ** e) / (e * 2.1) * np.sin(e * ratio * 1.2)
            priority = (s * np.sin(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
        elif 1 <= ratio <= 2:
            s1 = 0
            s2 = 0
            for f in range(1, 12):
                s1 += ((2 - ratio) ** f) / (f ** 2 + 1) * np.cos(f * ratio * 1.5)
            for g in range(1, 7):
                s2 += ((ratio - 1) ** g) / (g + 0.5) * np.sin(g * ratio * 2)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s1 + s2 + penalty + np.exp(-2 / (ratio + 0.1))
            for h in range(1, 6):
                priority += np.sin(h * ratio * i * 0.8) * ((ratio - 1) ** h) / h
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 18):
                s += ((1 - ratio) ** j) / (j * 3) * np.cos(j * item * 1.5)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 1.4) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 16):
                s += ((0.5 - ratio) ** l) / (l * 2) * np.cos(l * ratio * 2.5)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 1.5) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.3)
        else:
            s = 0
            for n in range(1, 12):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.6) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for o in range(1, 10):
                priority += ((0.2 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for p in range(1, 5):
            if (i + p) % 4 == 0:
                priority += np.sin(ratio * (i + p) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + p) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if i % 5 == 0 and bin_cap > item * 0.8:
            priority += np.exp(-ratio) * 3
            for q in range(1, 5):
                priority += np.sin(q * ratio * i) / (q + 0.5)
        if i % 2 == 1 and bin_cap < item:
            priority -= np.sqrt(bin_cap) * ratio * 1.5
            for r in range(1, 6):
                priority += np.cos(r * ratio * i * 0.9) * ((ratio - 0.7) ** r) / (r + 1)
        priorities[i] = priority
    return priorities
